import pypdf
import os
import json
import re

PDF_PATH = "d:/project/graphify/pdf/koreantree.pdf"
ASSET_DIR = "d:/project/graphify/assets/species"
os.makedirs(ASSET_DIR, exist_ok=True)

def update_structure():
    # 1. Parse TOC Text
    with open("d:/project/graphify/full_toc_text.txt", "r", encoding="utf-8") as f:
        toc_text = f.read()
    
    species_list = []
    # Better pattern for species in TOC
    # Matches: Name Scientific . 123
    pattern = re.compile(r'([๊ฐ-ํฃ]{2,})\s+([A-Z][a-z][A-Za-z\s\.\-x\(\)\']+)\s*[\s\.โข]*\s*(\d+)')
    
    for line in toc_text.split('\n'):
        m = pattern.search(line)
        if m:
            species_list.append({
                "name": m.group(1),
                "scientific_name": m.group(2).strip(),
                "page": int(m.group(3)),
                "summary": f"{m.group(3)}ํ์ด์ง ์๋ก์ข",
                "details": {"distribution": "๋ฐ์ดํฐ ์ถ์ถ ์ค...", "form": "๋ฐ์ดํฐ ์ถ์ถ ์ค..."}
            })

    # 2. Extract real data for specific ones
    reader = pypdf.PdfReader(PDF_PATH)
    targets = ["์ฐธ์ธ๋ฆฌ", "๋ฅ์ํ", "์กฐ๋ก์ธ๋ฆฌ"]
    
    for s in species_list:
        if s["name"] in targets:
            # Find physical page (offset logic)
            # Based on previous tests, Page 70 in TOC is physical page 82-84
            # We'll search in range
            found_idx = -1
            search_start = s["page"] + 10
            search_end = search_start + 15
            for idx in range(search_start, search_end):
                if idx >= len(reader.pages): break
                text = reader.pages[idx].extract_text()
                if s["name"] in text:
                    found_idx = idx
                    break
            
            if found_idx != -1:
                page = reader.pages[found_idx]
                # Save Image
                if len(page.images) > 0:
                    img_data = page.images[0].data
                    img_name = f"{s['name']}.png"
                    with open(os.path.join(ASSET_DIR, img_name), "wb") as fimg:
                        fimg.write(img_data)
                    s["image"] = f"assets/species/{img_name}"
                
                # Update description
                s["details"]["form"] = page.extract_text()[:400].replace('\n', ' ')

    # 3. Save to JSON
    final_data = {
        "book": "ํ๊ตญ์ ๋๋ฌด",
        "total_count": len(species_list),
        "large_categories": [{
            "name": "์ ์ฒด ์์ข",
            "middle_categories": [{
                "name": "์๋ฌผ ๋ชฉ๋ก",
                "small_categories": [{
                    "name": "์ผ๋ฐ ์์ข",
                    "species": species_list
                }]
            }]
        }]
    }
    
    with open("d:/project/graphify/botanical_structure.json", "w", encoding="utf-8") as f:
        json.dump(final_data, f, ensure_ascii=False, indent=2)
    
    return len(species_list)

if __name__ == "__main__":
    count = update_structure()
    print(f"Updated JSON with {count} species.")
